+struct MergeInterval {
+    start: u64,
+    len: u64,
+}
+
+#[cfg(test)]
+impl MergeInterval {
+    fn overlaps(self, other: Self) -> bool {
+        let self_end = self.start.saturating_add(self.len);
+        let other_end = other.start.saturating_add(other.len);
+        self.start < other_end && other.start < self_end
+    }
+}
