+#[cfg(test)]
+#[derive(Debug, Clone, Copy, PartialEq, Eq)]
+struct MergeClassification {
+    safety: MergeSafety,
+    proof_family: &'static str,
+    reason: &'static str,
+    obligations: &'static [&'static str],
+}
